def load_ws(fn): return openpyxl.load_workbook(os.path.join(DL,fn)).active
def cell(v,money=False):
    if v is None: return ""
    if isinstance(v,(int,float)):
        if money: return f"{v:,.2f}".replace(","," ")
        return f"{v:,.0f}".replace(","," ") if float(v).is_integer() else f"{v:,.2f}".replace(","," ")
    return str(v)
