def footer(c,doc):
    c.saveState(); c.setFont("DJ",7.5); c.setFillColor(GREY)
    c.drawString(LM,9*mm,"Аскан → CRM-Omnicomm · браузерный аудит демо-базы · конфиденциально")
    c.drawRightString(PAGE_W-RM,9*mm,"стр. %d"%doc.page)
    c.setStrokeColor(LGREY); c.setLineWidth(0.4); c.line(LM,12*mm,PAGE_W-RM,12*mm); c.restoreState()

